% Domain
x = linspace(-2*pi, 2*pi, 1000);

% Functions
y1 = cos(x);     % cos(x)
y2 = cos(-x);    % cos(-x) (equal to cos(x))

% Plot
figure %[output:755c0062]
plot(x, y1, 'b', 'LineWidth', 1.5)       % cos(x) %[output:755c0062]
hold on %[output:755c0062]
plot(x, y2, 'r--', 'LineWidth', 1.2)     % cos(-x) %[output:755c0062]
hold off %[output:755c0062]
xlabel('x') %[output:755c0062]
ylabel('Amplitude') %[output:755c0062]
title('cos(x) (blue) and cos(-x) (red dashed)') %[output:755c0062]
legend('cos(x)', 'cos(-x)', 'Location', 'Best') %[output:755c0062]
grid on %[output:755c0062]
axis tight %[output:755c0062]
%%
% Domain
x = linspace(-2*pi, 2*pi, 1000);

% Functions
y1 = sin(-x);    % sin(-x)
y2 = -sin(x);    % -sin(x), should match y1

% Plot
figure %[output:510bc426]
plot(x, y1, 'b', 'LineWidth', 1.5)       % sin(-x) %[output:510bc426]
hold on %[output:510bc426]
plot(x, y2, 'r--', 'LineWidth', 1.2)     % -sin(x) %[output:510bc426]
hold off %[output:510bc426]
xlabel('x') %[output:510bc426]
ylabel('Amplitude') %[output:510bc426]
title('sin(-x) (blue) and -sin(x) (red dashed)') %[output:510bc426]
legend('sin(-x)', '-sin(x)', 'Location', 'Best') %[output:510bc426]
grid on %[output:510bc426]
axis tight %[output:510bc426]

